<template>
  <div class="istadetail">
    <main>
      <div class="title">
        <h1>样品名称:{{ detail.productname }}</h1>
        <h6>产品批次:{{ detail.productNumber }}</h6>
        <h6>产品规格:{{ detail.modelId }}</h6>
        <h6>样品数量:{{ detail.objectCount }}</h6>
        <p>生产厂家:{{ detail.productCompanyName }}</p>
      </div>

      <!-- <van-button icon="edit" size="large">修改</van-button> -->
      <van-button icon="delete-o" size="large" @click="del()">删除</van-button>
    </main>
  </div>
</template>

<script>
import { mapMutations } from "vuex";
import { Dialog } from "vant";
export default {
  props: ["detail", "index"],
  methods: {
    ...mapMutations(["delsampleList"]),
    del(index) {
      Dialog.confirm({
        title: "删除此委托单",
        message: "确认删除？",
      })
        .then(() => {
          this.delsampleList(this.index);
          location. reload()
          // on confirm
        })
        .catch(() => {
          // on cancel
        });
    },
  },
};
</script>


