<template>
  <div class="istacard">
    <main>
      <div class="title">
        <h1>委托单编号:{{ detail.entrustCode }}</h1>
        <h6>
          订单状态:<van-tag plain type="primary">{{
            detail.status == "0" ? "未分任务" : "已分任务"
          }}</van-tag>
        </h6>
        <h6>下单时间:{{ detail.entrustTime }}</h6>
        <p>
          检测进程:
          <el-select
            @change="selectValue"
            v-model="value"
            size="mini"
            clearable
            placeholder="请选择"
          >
            <el-option
              v-for="item in options"
              :key="item.id"
              :label="item.label"
              :value="item.label"
            >
            </el-option>
          </el-select>
        </p>
      </div>
      <van-steps :active="active" active-color="#1989fa">
        <van-step>委托单提交 </van-step>
        <van-step>任务生成</van-step>
        <van-step>检测中 </van-step>
        <van-step>检测完成 </van-step>
        <!-- <van-step></van-step> -->
      </van-steps>
      <div class="button">
        <template v-if="active === '3'">
          <!-- <van-button round color="#7232dd" size="small">查看报告</van-button> -->
          <van-button round type="warning" size="small" @click="downloadcheck"
            >下载报告</van-button
          >
        </template>
        <template v-else>
          <van-button
            round
            type="info"
            size="small"
            @click="detailista(detail.entrustCode)"
            >委托单详情</van-button
          >
          <van-button
            round
            type="primary"
            size="small"
            @click="qrcode(detail.entrustCode)"
            >订单二维码</van-button
          >
          <van-button
            class="animate__animated animate__tada"
            round
            size="small"
            color="#7232dd"
            @click="once(detail.entrustCode)"
            >再来一单</van-button
          >
        </template>
      </div>
    </main>
  </div>
</template>

<script>
import { config } from "../utils/config";
import { once } from "../utils/once";
import { getistas } from "../utils/http/api";
import { mapMutations } from "vuex";

export default {
  props: ["detail"],
  created() {
    this.detail.list.map((item) => {
      this.options.push({
        label: item.sampleName,
        value: item.checkStat === null ? 1 : item.checkStat,
      });
      this.options_copy.push({
        label: item.sampleName,
        value: item.checkStat === null ? 1 : item.checkStat,
        id: item.sampleId,
      });
    });
  },
  methods: {
    ...mapMutations(["setsampleList", "setentrustInfo", "deltotalsampleList"]),

    once(entrustCode) {
      getistas(entrustCode).then((res) => {
        console.log(res);

        if (res.data.code === 200) {
          this.deltotalsampleList();
          let data = once(res.data.data);
          // 设置检测列表
          data.sampleList.forEach((item) => {
            this.setsampleList(item);
          });
          // 设置检测项
          this.setentrustInfo(data.entrustInfo);

          this.$router.push({ name: "ista" });
        }
      });
    },
    downloadcheck() {
      // 下载报告
      window.location.href = `${config.downloadhttp}/lims/entrust/downloadReport?sampleId=${this.checkid}`;

      // this.$router.push({
      //   name: "loadcheck",
      //   query: { sampleId: this.checkid, entrustId: this.detail.entrustCode },
      // });
    },
    selectValue(value) {
      if (value === null || value === "") return;
      this.active = this.options_copy.filter((item) => {
        return item.label === value;
      })[0].value;
      // 设置下载检测报告参数
      this.checkid = this.options_copy.filter((item) => {
        return item.label === value;
      })[0].id;
    },
    detailista(entrustId) {
      this.$router.push({
        name: "Istaproductdetail",
        query: { entrustId },
      });
    },
    qrcode(code) {
      this.$router.push({
        name: "qrcode",
        query: { code: code, success: false },
      });
    },
  },
  data() {
    return {
      active: 0,
      value: "",
      options: [],
      options_copy: [],
      checkid: "",
      typeoptions: [
        {
          label: 1,
          value: 0,
        },
        {
          label: 2,
          value: 1,
        },
        {
          label: 4,
          value: 2,
        },
        {
          label: 3,
          value: 3,
        },
      ],
    };
  },
};
</script>


<style lang="less">
.istacard {
  width: 7.5rem;
  // height: 4rem;
  padding: 0rem 0.1rem;
  margin-top: 10px;
  box-sizing: border-box;
  // background: khaki;
  main {
    width: 100%;
    height: 100%;
    border-radius: 0.2rem;
    background: white;
    overflow: hidden;
    display: flex;
    flex-direction: column;

    .title {
      display: flex;
      flex-direction: column;
      margin: 0.2rem 0.2rem 0px 0.2rem;
      padding: 0.2rem 0.2rem 0px 0.2rem;
      box-sizing: border-box;
    }
    h1 {
      font-size: 16px;
      font-weight: 600;
      // margin-top:5px;
    }
    h6 {
      font-size: 0.24rem;
      font-weight: 400;
      margin-top: 0.1rem;
    }
    p {
      font-size: 0.24rem;
      margin-top: 0.1rem;
      margin-bottom: 0.1rem;
    }
  }
  .button {
    display: flex;
    justify-content: space-around;
    align-items: center;
    padding-bottom: 10px;
  }
}
</style>